//${AOs::AO_ESP32C::ReceiveCompleteCallback} .................................
void AO_ESP32C::ReceiveCompleteCallback(
    DRV::ESP32C3::Event  event,
    DRV::ESP32C3*  caller,
    uint8_t*  data)
{
    // check event type
    if(event == DRV::ESP32C3::Event::RespReceived)
    {
        // copy data to buffer
        uint32_t len =strnlen((char*)data, sizeof(rx_buffer));
        if(len> sizeof(rx_buffer))
        {
            len = sizeof(rx_buffer);
        }
        memcpy(rx_buffer, data, len);
        rx_buffer[len] = 0;
        QP::QEvt *evt = Q_NEW(QP::QEvt, ESP32C_OK_SIG);
        this->POST(evt,caller);

    }else if( event == DRV::ESP32C3::Event::RespErr )
    {
        QP::QEvt *evt = Q_NEW(QP::QEvt, ESP32C_ERR_SIG);
        this->POST(evt,caller);
    }

}

