//${AOs::AO_ESP32C::GetFreeSocketId} .........................................
uint8_t AO_ESP32C::GetFreeSocketId(DRV::ESP32C3::LinkId* startOutput_socketId) {
    uint8_t retVal = 0;
    for( uint8_t id = (uint8_t)(*startOutput_socketId);
         id<(uint8_t)DRV::ESP32C3::LinkIdMax;
         id++)
    {
        if(socket_status[id] == ESP32C_SOCKET_STATUS_CLOSE)
        {
            /* unopened socket found */
            retVal = 1;
            *startOutput_socketId = (DRV::ESP32C3::LinkId)id;
            TRACE_AO_ESP32C("GotId%d", id);
            break;
        }
    }

    if(!retVal)
    {
        TRACE_AO_ESP32C("ID_GET_FAI");
    }

    return retVal;
}

